def median(l: list):
    """Return median of elements in the list l.
    >>> median([3, 1, 2, 4, 5])
    3
    >>> median([-10, 4, 6, 1000, 10, 20])
    15.0
    """
    m = len(l)
    if m == 0:
        return None
    else:
        l = sorted(l)
        mid = int(math.floor(m / 2))
        # If len of l is odd, median = l[mid], else
        # median = mean of l[mid], l[mid+1]
        if m % 2 != 0:
            return l[mid]
        else:
            return mean([l[mid], l[mid + 1]])

