def solve(s):
    """You are given a string s.
    if s[i] is a letter, reverse its case from lower to upper or vise versa, 
    otherwise keep it as it is.
    If the string contains no letters, reverse the string.
    The function should return the resulted string.
    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """
    result = []
    isalpha = False
    for c in s:
        if c.isalpha():
            isalpha = True
            result.append(c.upper() if c == c.lower() else c.lower())
        else:
            result.append(c)

    return ''.join(result[::-1]) if isalpha else ''.join(result)

